    const StudentChat = ({ className, onBack }) => {
      const [messages, setMessages] = useState([
        { role: 'bot', text: `Hey there! I'm your AI tutor for ${className}. I've got all the lecture notes and the syllabus ready. What's on your mind?` }
      ]);
      const [input, setInput] = useState('');

      const send = () => {
        if (!input) return;
        const userMsg = { role: 'user', text: input };
        setMessages([...messages, userMsg]);
        setInput('');

        // Simulate RAG response
        setTimeout(() => {
          setMessages(prev => [...prev, { 
            role: 'bot', 
            text: "According to the Week 1 Mechanics handout, velocity is the rate of change of displacement, while speed is just the rate of change of distance. Velocity is a vector (it has direction!), speed is a scalar. Check page 4 of the handout for the formulas!" 
