                {m.text}
              </div>
            ))}
          </main>

          <footer style={{ padding: '24px 0', background: 'var(--surface)', borderTop: '1px solid var(--border)', position: 'sticky', bottom: 0 }}>
            <div className="container" style={{ maxWidth: '720px', display: 'flex', gap: '12px' }}>
              <input 
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyPress={e => e.key === 'Enter' && send()}
                placeholder="Ask your class tutor anything..." 
                style={{ flex: 1, padding: '16px 24px', borderRadius: 'var(--radius-xl)', border: '1px solid var(--border)', background: 'var(--bg)', outline: 'none', fontSize: '16px', fontFamily: 'var(--font-body)' }}
