      const [currentScreen, setCurrentScreen] = useState('landing');
      const [selectedClass, setSelectedClass] = useState(null);
      const [accent, setAccent] = useState('warm');

      return (
        <div data-theme={accent}>
          {currentScreen === 'landing' && <LandingScreen onStart={(scr) => setCurrentScreen(scr)} />}
          {currentScreen === 'teacher-dash' && <TeacherDash onSelectClass={(c) => { setSelectedClass(c); setCurrentScreen('teacher-detail'); }} />}
          {currentScreen === 'teacher-detail' && <ClassDetail cls={selectedClass} onBack={() => setCurrentScreen('teacher-dash')} />}
          {currentScreen === 'student-home' && <StudentHome onJoin={(name) => { setSelectedClass({name}); setCurrentScreen('student-chat'); }} />}
          {currentScreen === 'student-chat' && <StudentChat className={selectedClass?.name} onBack={() => setCurrentScreen('student-home')} />}

          <div id="tweaks-panel">
            <span className="tweak-label">Brand Color</span>
            <div className="tweak-grid">
              <div className={`tweak-dot ${accent === 'warm' ? 'active' : ''}`} style={{ background: 'oklch(64% 0.13 28)' }} onClick={() => setAccent('warm')}></div>
              <div className={`tweak-dot ${accent === 'blue' ? 'active' : ''}`} style={{ background: 'oklch(60% 0.15 250)' }} onClick={() => setAccent('blue')}></div>
              <div className={`tweak-dot ${accent === 'green' ? 'active' : ''}`} style={{ background: 'oklch(60% 0.15 150)' }} onClick={() => setAccent('green')}></div>
            </div>
          </div>

          <nav id="prototype-nav">
            <button className={currentScreen === 'landing' ? 'active' : ''} onClick={() => setCurrentScreen('landing')}>Landing</button>
            <button className={currentScreen.startsWith('teacher') ? 'active' : ''} onClick={() => setCurrentScreen('teacher-dash')}>Teacher</button>
            <button className={currentScreen.startsWith('student') ? 'active' : ''} onClick={() => setCurrentScreen('student-home')}>Student</button>
          </nav>
        </div>
      );
    }

    const root = ReactDOM.createRoot(document.getElementById('root'));
    root.render(<App />);
  </script>
