+export const SESSION_TTL_MS = 60 * 60 * 1000;
+
+export type ChatMessage = {
+  id: string;
+  role: "user" | "assistant";
+  content: string;
+  createdAt?: number;
+};
+
+export type StoredClass = {
+  classId: string;
+  className: string;
+  slug: string;
+  lastVisited: number;
+};
+
+export function sessionIsExpired(lastVisited: number | undefined, now = Date.now()): boolean {
+  if (!lastVisited) {
+    return false;
+  }
+
+  return now - lastVisited > SESSION_TTL_MS;
+}
+
+export function getFreshMessages<TMessage>(
+  messages: TMessage[],
+  lastVisited: number | undefined,
+  now = Date.now()
+): TMessage[] {
+  return sessionIsExpired(lastVisited, now) ? [] : messages;
+}
+
+export function classListAfterVisit(
+  existing: StoredClass[],
+  visit: {
+    classId: string;
+    className: string;
+    slug: string;
+    visitedAt: number;
+  }
+): StoredClass[] {
+  const withoutClass = existing.filter((item) => item.classId !== visit.classId);
+
+  return [
+    {
+      classId: visit.classId,
+      className: visit.className,
+      slug: visit.slug,
+      lastVisited: visit.visitedAt
+    },
+    ...withoutClass
+  ].sort((left, right) => right.lastVisited - left.lastVisited);
+}
