+export type RagChunk = {
+  content: string;
+  source: string;
+  index: number;
+};
+
+export function chunkText(text: string, chunkSize = 500, overlap = 80): RagChunk[] {
+  const words = text.trim().split(/\s+/).filter(Boolean);
+
+  if (words.length === 0) {
+    return [];
+  }
+
+  const step = Math.max(1, chunkSize - overlap);
+  const chunks: RagChunk[] = [];
+
+  for (let start = 0; start < words.length; start += step) {
+    const content = words.slice(start, start + chunkSize).join(" ");
+    chunks.push({
+      content,
+      source: "Pasted material",
+      index: chunks.length
+    });
+
+    if (start + chunkSize >= words.length) {
+      break;
+    }
+  }
+
+  return chunks;
+}
+
+export function buildRagPrompt({
+  question,
+  className,
+  chunks
+}: {
+  question: string;
+  className: string;
+  chunks: RagChunk[];
+}): string {
+  const context =
+    chunks.length > 0
+      ? chunks
+          .map(
+            (chunk) =>
+              `[${chunk.index + 1}] Source: ${chunk.source}\n${chunk.content.trim()}`
+          )
+          .join("\n\n")
+      : "No retrieved class material was found.";
+
+  return `You are Askfree, a concise classroom tutor for ${className}.
+
+Use only the class context below. If the answer is not in the context, say you do not see it in the teacher's materials and suggest what the student should ask the teacher.
+
+Class context:
+${context}
+
+Student question:
+${question}
+
+Answer with a friendly explanation and cite the source names when useful.`;
+}
+
+export function demoTutorAnswer(question: string): string {
+  const normalized = question.toLowerCase();
+
+  if (normalized.includes("velocity") || normalized.includes("speed")) {
+    return "According to the Week 1 Mechanics notes, velocity is displacement over time and includes direction. Speed only measures distance over time, so it is scalar.";
+  }
+
+  if (normalized.includes("syllabus") || normalized.includes("exam")) {
+    return "The syllabus says weekly practice counts most, with exams used to check whether the core ideas are sticking. Review the worksheet examples before class discussion.";
+  }
+
+  return "I found related class material, but not an exact answer. Try asking about a specific worksheet, lecture title, or term from the notes so I can ground the response more tightly.";
+}
