+    class_id: classId,
+    type: "text",
+    content: chunk.content,
+    metadata: {
+      ...metadata,
+      source: chunk.source,
+      chunk_index: chunk.index
+    }
+  }));
+
+  const { error } = await supabaseAdmin.from("materials").insert(rows);
+
+  if (error) {
+    throw new Error(error.message);
+  }
+
+  return {
