+  type text not null default 'text',
+  content text not null,
+  metadata jsonb default '{}'::jsonb,
+  embedding vector(1536),
+  created_at timestamptz default timezone('utc'::text, now()) not null
+);
+
+create index if not exists materials_class_id_idx on public.materials(class_id);
+create index if not exists materials_embedding_idx on public.materials
+using ivfflat (embedding vector_cosine_ops)
+with (lists = 100);
+
+create or replace function public.match_materials(
+  query_embedding vector(1536),
+  match_threshold float,
+  match_count int,
+  p_class_id uuid
+)
+returns table (
+  id uuid,
+  class_id uuid,
+  content text,
+  metadata jsonb,
+  similarity float
+)
+language sql stable
+as $$
+  select
+    materials.id,
+    materials.class_id,
+    materials.content,
+    materials.metadata,
+    1 - (materials.embedding <=> query_embedding) as similarity
+  from public.materials
+  where materials.class_id = p_class_id
+    and materials.embedding is not null
+    and 1 - (materials.embedding <=> query_embedding) > match_threshold
+  order by materials.embedding <=> query_embedding
+  limit match_count;
+$$;
