+export type MaterialUploadType = "pdf" | "text" | "unsupported";
+
+export function detectMaterialType(fileName: string, mimeType: string): MaterialUploadType {
+  const normalizedName = fileName.toLowerCase();
+  const normalizedType = mimeType.toLowerCase();
+
+  if (normalizedType === "application/pdf" || normalizedName.endsWith(".pdf")) {
+    return "pdf";
+  }
+
+  if (
+    normalizedType.startsWith("text/") ||
+    normalizedName.endsWith(".txt") ||
+    normalizedName.endsWith(".md") ||
+    normalizedName.endsWith(".csv")
+  ) {
+    return "text";
+  }
+
+  return "unsupported";
+}
+
+export function materialSourceName(fileName: string): string {
+  const cleaned = fileName.replace(/[\\/]+/g, " ").replace(/\s+/g, " ").trim();
+  return cleaned || "Uploaded material";
+}
+
+export async function extractTextFromUpload(file: File): Promise<{
+  content: string;
+  source: string;
+  type: MaterialUploadType;
+}> {
+  const source = materialSourceName(file.name);
+  const type = detectMaterialType(file.name, file.type);
+
+  if (type === "unsupported") {
+    throw new Error("Only PDF and plain text uploads are supported right now.");
+  }
+
+  if (type === "text") {
+    return {
+      content: await file.text(),
+      source,
+      type
+    };
+  }
+
+  const pdfParse = (await import("pdf-parse")).default;
+  const buffer = Buffer.from(await file.arrayBuffer());
+  const parsed = await pdfParse(buffer);
+
+  return {
+    content: parsed.text,
+    source,
+    type
+  };
+}
