import { ArrowLeft, Send } from "lucide-react";
import Link from "next/link";
import { FormEvent, useEffect, useState } from "react";

import { useLocalStorage } from "@/hooks/useLocalStorage";
import { ChatMessage, classListAfterVisit, getFreshMessages, StoredClass } from "@/lib/student-session";

export function ChatWindow({
  classId,
  className,
  slug
}: {
  classId: string;
  className: string;
  slug: string;
}) {
  const [input, setInput] = useState("");
  const [busy, setBusy] = useState(false);
  const [lastVisited, setLastVisited] = useLocalStorage<number | undefined>(
    `askfree:last-visited:${classId}`,
    undefined
  );
  const [storedClasses, setStoredClasses] = useLocalStorage<StoredClass[]>("askfree:classes", []);
  const [messages, setMessages] = useLocalStorage<ChatMessage[]>(`askfree:chat:${classId}`, [
    {
      id: "welcome",
      role: "assistant",
      content: `Hey there. I am your Askfree tutor for ${className}. Ask me anything from the teacher's materials.`,
      createdAt: 0
    }
  ]);

  useEffect(() => {
    setStoredClasses(
      classListAfterVisit(storedClasses, {
        classId,
        className,
        slug,
        visitedAt: Date.now()
      })
    );
    setMessages(getFreshMessages(messages, lastVisited, Date.now()));
    setLastVisited(Date.now());
    // This visit registration intentionally runs once per class page mount.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [classId]);

  async function onSubmit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    const question = input.trim();

    if (!question || busy) {
      return;
    }

    const userMessage: ChatMessage = {
      id: crypto.randomUUID(),
      role: "user",
      content: question,
      createdAt: Date.now()
    };
    setMessages((current) => [...current, userMessage]);
    setInput("");
    setBusy(true);

    const response = await fetch("/api/chat", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ classId, className, question })
    });
    const result = (await response.json()) as { answer?: string; error?: string };

    setMessages((current) => [
      ...current,
      {
        id: crypto.randomUUID(),
        role: "assistant",
        content: result.answer ?? result.error ?? "I could not answer that yet.",
        createdAt: Date.now()
      }
    ]);
    setLastVisited(Date.now());
    setBusy(false);
  }

  return (
    <main className="chat-page">
      <div>
        <div className="container" style={{ paddingTop: 22 }}>
          <Link className="button ghost" href="/">
            <ArrowLeft size={16} />
            My classes
          </Link>
        </div>
        <div className="messages" aria-live="polite">
          {messages.map((message) => (
            <div className={`message ${message.role === "user" ? "user" : ""}`} key={message.id}>
              {message.content}
            </div>
          ))}
          {busy ? <div className="message">Checking the class materials...</div> : null}
        </div>
      </div>
      <div className="composer-wrap">
        <form className="composer" onSubmit={onSubmit}>
          <input
            className="input"
            onChange={(event) => setInput(event.target.value)}
            placeholder="Ask your class tutor anything..."
            value={input}
          />
          <button className="button primary icon" disabled={busy} title="Send" type="submit">
            <Send size={18} />
          </button>
        </form>
      </div>
    </main>
  );
}

