        : result.error ?? "Could not process material."
    );
    if (response.ok) {
      setContent("");
      setFile(null);
    }
    setBusy(false);
  }

  function onFileChange(event: ChangeEvent<HTMLInputElement>) {
    setFile(event.target.files?.[0] ?? null);
  }

  function uploadFile(selectedFile: File) {
    const formData = new FormData();
    formData.append("classId", classId);
    formData.append("file", selectedFile);

    return fetch("/api/ingest", {
      method: "POST",
      body: formData
    });
  }

  return (
    <form className="upload-zone" onSubmit={onSubmit}>
      <div className="form-stack" style={{ width: "min(540px, calc(100% - 32px))" }}>
        <FileUp aria-hidden size={34} style={{ margin: "0 auto", color: "var(--accent)" }} />
        <h3>Add Course Material</h3>
        <label className="button" style={{ justifySelf: "center" }}>
          Choose PDF
          <input
            accept="application/pdf,.pdf,text/plain,.txt,.md"
            onChange={onFileChange}
            style={{ display: "none" }}
            type="file"
          />
        </label>
        {file ? <p className="muted">Selected: {file.name}</p> : null}
        <textarea
          className="textarea"
          onChange={(event) => setContent(event.target.value)}
          placeholder="Or paste worksheet text, a syllabus excerpt, or article notes..."
          value={content}
        />
        <button className="button primary" disabled={busy || (!file && content.trim().length === 0)} type="submit">
          {busy ? "Processing" : file ? "Upload PDF" : "Process material"}
        </button>
        <p className="muted">{message}</p>
      </div>
    </form>
  );
}
